-- Confetti — task library seed (v1.1, 140 tasks)
-- Generated from task_library.json — regenerate rather than hand-edit.
on conflict (id) do update set
  title=excluded.title, category=excluded.category, phase=excluded.phase,
  lead_weeks=excluded.lead_weeks, duration_weeks=excluded.duration_weeks,
  priority=excluded.priority, depends_on=excluded.depends_on, guidance=excluded.guidance,
  typical_cost_gbp=excluded.typical_cost_gbp, ask_suppliers=excluded.ask_suppliers,
  wedding_types=excluded.wedding_types, library_version=excluded.library_version;
